using System;
using System.ComponentModel.Composition;
using XrmToolBox.Extensibility;
using XrmToolBox.Extensibility.Interfaces;

namespace PluginDebugger
{
    /// <summary>
    /// XrmToolBox tool registration (MEF). Discovered by the host via the
    /// <see cref="IXrmToolBoxPlugin"/> export; <see cref="GetControl"/> creates the UI.
    /// </summary>
    [Export(typeof(IXrmToolBoxPlugin))]
    [ExportMetadata("Name", "PluginXray")]
    [ExportMetadata("Description", "Tool that helps you debug the Dataverse Plugin/Workflow")]
    [ExportMetadata("BackgroundColor", "White")]
    [ExportMetadata("PrimaryFontColor", "Black")]
    [ExportMetadata("SecondaryFontColor", "DarkGray")]
    // SmallImageBase64 / BigImageBase64 are REQUIRED metadata keys on XrmToolBox's IPluginMetadata
    // (no default value). Omitting them makes MEF's metadata-view filter silently drop the export,
    // so the tool is scanned but never listed. The values below are the PluginXray icons
    // (icons/PluginXray-32.png and icons/PluginXray-128.png) encoded as base64 PNG.
    [ExportMetadata("SmallImageBase64", SmallImageBase64)]
    [ExportMetadata("BigImageBase64", BigImageBase64)]
    public class PluginDebuggerPlugin : PluginBase
    {
        // 32x32 tool-list icon (icons/PluginXray-32.png).
        private const string SmallImageBase64 =
            "";

        // 128x128 detail icon (icons/PluginXray-128.png).
        private const string BigImageBase64 =
            "";

        public override IXrmToolBoxPluginControl GetControl()
        {
            return new PluginDebuggerControl();
        }
    }
}
